 88→// ParseNextData extracts the __NEXT_DATA__ JSON from BigFuture HTML and
 89→// returns the parsed college data.
 90→func ParseNextData(html []byte) (*BigFutureData, error) {
 91→	startIdx := bytes.Index(html, nextDataStart)
 92→	if startIdx < 0 {
 93→		return nil, fmt.Errorf("deadlines: bigfuture: __NEXT_DATA__ script tag not found")
 94→	}
 95→	jsonStart := startIdx + len(nextDataStart)
 96→
 97→	endIdx := bytes.Index(html[jsonStart:], nextDataEnd)
 98→	if endIdx < 0 {
 99→		return nil, fmt.Errorf("deadlines: bigfuture: __NEXT_DATA__ closing script tag not found")
100→	}
101→
102→	jsonBytes := html[jsonStart : jsonStart+endIdx]
103→
104→	var envelope nextDataEnvelope
105→	if err := json.Unmarshal(jsonBytes, &envelope); err != nil {
106→		return nil, fmt.Errorf("deadlines: bigfuture: parse __NEXT_DATA__ JSON: %w", err)
107→	}
108→
109→	data := envelope.Props.PageProps.CollegeData
110→	return &data, nil
111→}
