172→// convertDate converts a BigFuture date string (MM/DD/9999) to YYYY-MM-DD
173→// using the given year. Returns empty string for null, empty, or unparseable dates.
174→func convertDate(s string, year int) string {
175→	s = strings.TrimSpace(s)
176→	if s == "" || s == "null" {
177→		return ""
178→	}
179→
180→	// Expected format: MM/DD/YYYY (where YYYY is often 9999).
181→	parts := strings.Split(s, "/")
182→	if len(parts) != 3 {
183→		return ""
184→	}
185→
186→	month := parts[0]
187→	day := parts[1]
188→
189→	// Validate month and day are numeric and in range.
190→	if len(month) < 1 || len(month) > 2 || len(day) < 1 || len(day) > 2 {
191→		return ""
192→	}
193→
194→	return fmt.Sprintf("%04d-%s-%s", year, zeroPad(month), zeroPad(day))
195→}
196→
197→// zeroPad ensures a 1-2 digit string is zero-padded to 2 digits.
198→func zeroPad(s string) string {
199→	if len(s) == 1 {
200→		return "0" + s
201→	}
202→	return s
203→}
